'use client';

import { useState } from 'react';
import { useAuth } from '@/components/auth-provider';
import Image from 'next/image';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Trash2, ChevronLeft, ChevronRight, ImageIcon } from 'lucide-react';
import { toast } from 'sonner';

interface PostImage {
  id: string;
  post_id: string;
  image_url: string;
  sort_order: number;
}

interface Post {
  id: string;
  category: string;
  subcategory: string | null;
  title: string;
  content: string | null;
  thumbnail_url: string | null;
  created_at: string;
  images: PostImage[];
}

interface BoardDetailModalProps {
  post: Post | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onDelete: () => void;
}

export function BoardDetailModal({
  post,
  open,
  onOpenChange,
  onDelete,
}: BoardDetailModalProps) {
  const { hasPermission } = useAuth();
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);

  if (!post) return null;
  const images = post.images || [];

  const handlePrevImage = () => {
    setCurrentImageIndex((prev) =>
      prev === 0 ? images.length - 1 : prev - 1
    );
  };

  const handleNextImage = () => {
    setCurrentImageIndex((prev) =>
      prev === images.length - 1 ? 0 : prev + 1
    );
  };

  const handleDeleteClick = async () => {
    if (!hasPermission(['SUPER_ADMIN'])) return;
    if (!confirm('정말로 삭제하시겠습니까?')) return;

    setIsDeleting(true);
    try {
      const res = await fetch(`/api/posts/${post.id}`, {
        method: 'DELETE',
      });

      if (res.ok) {
        toast.success('글이 삭제되었습니다.');
        onOpenChange(false);
        onDelete();
      } else {
        toast.error('삭제에 실패했습니다.');
      }
    } catch {
      toast.error('삭제 중 오류가 발생했습니다.');
    } finally {
      setIsDeleting(false);
    }
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('ko-KR', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  };

  return (
    <>
      <Dialog open={open} onOpenChange={onOpenChange}>
        <DialogContent className="sm:max-w-3xl max-h-[90vh] overflow-y-auto">
          <DialogHeader className="flex flex-row items-start justify-between">
            <div>
              <DialogTitle className="text-2xl">{post.title}</DialogTitle>
              <DialogDescription className="sr-only">게시글 상세 내용</DialogDescription>
              <p className="text-sm text-muted-foreground mt-1">
                {formatDate(post.created_at)}
              </p>
            </div>
            <Button
              variant="destructive"
              size="sm"
              onClick={handleDeleteClick}
              disabled={isDeleting}
              className="flex items-center gap-2"
            >
              <Trash2 className="h-4 w-4" />
              삭제
            </Button>
          </DialogHeader>
          
          <div className="space-y-6 mt-4">
            {/* Images */}
            {images.length > 0 && (
              <div className="relative">
                <div className="aspect-video relative bg-muted">
                  <Image
                    src={images[currentImageIndex]?.image_url || 'https://via.placeholder.com/150'}
                    alt={`${post.title} - ${currentImageIndex + 1}`}
                    fill
                    className="object-contain"
                  />
                </div>
                {images.length > 1 && (
                  <>
                    <Button
                      variant="secondary"
                      size="icon"
                      className="absolute left-2 top-1/2 -translate-y-1/2"
                      onClick={handlePrevImage}
                    >
                      <ChevronLeft className="h-4 w-4" />
                    </Button>
                    <Button
                      variant="secondary"
                      size="icon"
                      className="absolute right-2 top-1/2 -translate-y-1/2"
                      onClick={handleNextImage}
                    >
                      <ChevronRight className="h-4 w-4" />
                    </Button>
                    <div className="absolute bottom-2 left-1/2 -translate-x-1/2 bg-foreground/80 text-background px-2 py-1 text-sm">
                      {currentImageIndex + 1} / {images.length}
                    </div>
                  </>
                )}
              </div>
            )}

            {/* Content */}
            {post.content && (
              <div className="p-4 bg-muted">
                <p className="whitespace-pre-wrap text-foreground leading-relaxed">
                  {post.content}
                </p>
              </div>
            )}
          </div>
        </DialogContent>
      </Dialog>

      
    </>
  );
}
