'use client';

import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '@/components/auth-provider';
import Image from 'next/image';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Plus, FileText, ImageIcon } from 'lucide-react';
import { BoardFormModal } from '@/components/board-form-modal';
import { BoardDetailModal } from '@/components/board-detail-modal';

interface PostImage {
  id: string;
  post_id: string;
  image_url: string;
  sort_order: number;
}

interface Post {
  id: string;
  category: string;
  subcategory: string | null;
  title: string;
  content: string | null;
  thumbnail_url: string | null;
  created_at: string;
  images: PostImage[];
}

interface BoardListProps {
  category: string;
  subcategory: string;
}

export function BoardList({ category, subcategory }: BoardListProps) {
  const { hasPermission } = useAuth();
  const [posts, setPosts] = useState<Post[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [showFormModal, setShowFormModal] = useState(false);
  const [selectedPost, setSelectedPost] = useState<Post | null>(null);
  const [showDetailModal, setShowDetailModal] = useState(false);

  const fetchPosts = useCallback(async () => {
    try {
      const res = await fetch(`/api/posts?category=${category}&subcategory=${subcategory}`);
      if (res.ok) {
        const data = await res.json();
        setPosts(data);
      }
    } catch (error) {
      console.error('Failed to fetch posts:', error);
    } finally {
      setIsLoading(false);
    }
  }, [category, subcategory]);

  useEffect(() => {
    fetchPosts();
  }, [fetchPosts]);

  const handleAddClick = () => {
    if (!hasPermission(['SUPER_ADMIN'])) return;
    setShowFormModal(true);
  };

  const handleFormSuccess = () => {
    fetchPosts();
    setShowFormModal(false);
  };

  const handlePostClick = (post: Post) => {
    setSelectedPost(post);
    setShowDetailModal(true);
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('ko-KR', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
  };

  if (isLoading) {
    return (
      <div className="space-y-4">
        {[...Array(5)].map((_, i) => (
          <Card key={i} className="p-4">
            <div className="flex gap-4">
              <div className="w-20 h-20 bg-muted animate-pulse" />
              <div className="flex-1 space-y-2">
                <div className="h-5 bg-muted animate-pulse w-3/4" />
                <div className="h-4 bg-muted animate-pulse w-1/4" />
              </div>
            </div>
          </Card>
        ))}
      </div>
    );
  }

  return (
    <>
      <div className="mb-6">
        <Button onClick={handleAddClick} className="flex items-center gap-2">
          <Plus className="h-4 w-4" />
          글 작성
        </Button>
      </div>

      {posts.length === 0 ? (
        <Card className="p-12 text-center">
          <div className="flex flex-col items-center gap-4 text-muted-foreground">
            <FileText className="h-12 w-12" />
            <p>등록된 글이 없습니다.</p>
            <p className="text-sm">글 작성 버튼을 눌러 첫 글을 등록하세요.</p>
          </div>
        </Card>
      ) : (
        <div className="space-y-3">
          {posts.map((post) => (
            <Card
              key={post.id}
              className="overflow-hidden cursor-pointer hover:border-primary transition-colors"
              onClick={() => handlePostClick(post)}
            >
              <CardContent className="p-4">
                <div className="flex gap-4">
                  {/* Thumbnail */}
                  <div className="flex-shrink-0 w-20 h-20 bg-muted relative">
                    {post.thumbnail_url ? (
                      <Image
                        src={post.thumbnail_url}
                        alt={post.title}
                        fill
                        className="object-cover"
                      />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center">
                        <ImageIcon className="h-8 w-8 text-muted-foreground" />
                      </div>
                    )}
                  </div>

                  {/* Content */}
                  <div className="flex-1 min-w-0">
                    <h3 className="font-medium text-foreground truncate">{post.title}</h3>
                    <p className="text-sm text-muted-foreground mt-1">
                      {formatDate(post.created_at)}
                    </p>
                    {post.content && (
                      <p className="text-sm text-muted-foreground mt-2 line-clamp-2">
                        {post.content}
                      </p>
                    )}
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      

      <BoardFormModal
        open={showFormModal}
        onOpenChange={setShowFormModal}
        onSuccess={handleFormSuccess}
        category={category}
        subcategory={subcategory}
      />

      <BoardDetailModal
        post={selectedPost}
        open={showDetailModal}
        onOpenChange={setShowDetailModal}
        onDelete={fetchPosts}
      />
    </>
  );
}
